import{_ as e,o as t,c as l,a2 as i}from"./chunks/framework.BilZITcA.js";const u=JSON.parse('{"title":"Course Map","description":"浙江大学计算机科学与技术课程笔记总览","frontmatter":{"title":"Course Map","description":"浙江大学计算机科学与技术课程笔记总览"},"headers":[],"relativePath":"logic.md","filePath":"logic.md","lastUpdated":1782225651000}'),s={name:"logic.md"};function r(o,a,n,c,d,m){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="hello-zjuer" tabindex="-1">Hello, ZJUer! <a class="header-anchor" href="#hello-zjuer" aria-label="Permalink to &quot;Hello, ZJUer!&quot;">​</a></h1><p>Welcome to <strong>My Note</strong>.</p><p>这里整理的是我在学习浙江大学计算机科学与技术相关课程时积累的笔记、推导、代码、易错点与复习内容。</p><p>这些内容不是标准答案，也不追求“一次写完”。它们会随着学习不断补充、修正和重构。</p><blockquote><p>These notes are your treasure. Start your journey, keep thinking, and enjoy learning.</p></blockquote><nav class="table-of-contents"><ul><li><a href="#start-here">Start Here</a></li><li><a href="#course-map">Course Map</a><ul><li><a href="#fundamentals-of-programming-and-algorithms">Fundamentals of Programming and Algorithms</a></li><li><a href="#digital-logic-design">Digital Logic Design</a></li><li><a href="#fundamentals-of-data-structure">Fundamentals of Data Structure</a></li><li><a href="#discrete-mathematics">Discrete Mathematics</a></li><li><a href="#computer-organization">Computer Organization</a></li></ul></li><li><a href="#study-checklist">Study Checklist</a></li><li><a href="#a-small-reminder">A Small Reminder</a></li></ul></nav><h2 id="start-here" tabindex="-1">Start Here <a class="header-anchor" href="#start-here" aria-label="Permalink to &quot;Start Here&quot;">​</a></h2><p>这套笔记目前主要覆盖以下课程：</p><ul><li>程序设计与算法基础</li><li>数字逻辑设计</li><li>数据结构基础</li><li>离散数学</li><li>计算机组成</li></ul><p>建议不要只把它当作考前速记资料。</p><p>更好的使用方式是：</p><ol><li>先阅读课程对应章节，建立基本概念。</li><li>遇到不懂的地方，通过右上角搜索定位关键词。</li><li>结合例题、代码和图示理解过程。</li><li>将自己容易错的内容补充进笔记。</li><li>在复习时回来看重点、公式与易错点。</li></ol><h2 id="course-map" tabindex="-1">Course Map <a class="header-anchor" href="#course-map" aria-label="Permalink to &quot;Course Map&quot;">​</a></h2><h3 id="fundamentals-of-programming-and-algorithms" tabindex="-1">Fundamentals of Programming and Algorithms <a class="header-anchor" href="#fundamentals-of-programming-and-algorithms" aria-label="Permalink to &quot;Fundamentals of Programming and Algorithms&quot;">​</a></h3><p>程序设计与算法基础。</p><p>主要包括程序设计思维、基础算法、代码实现与常见题型分析。</p><p><a href="/my_note/note-cs-code-cleaned.html">进入课程笔记 →</a></p><hr><h3 id="digital-logic-design" tabindex="-1">Digital Logic Design <a class="header-anchor" href="#digital-logic-design" aria-label="Permalink to &quot;Digital Logic Design&quot;">​</a></h3><p>数字逻辑设计。</p><p>主要包括数制系统、布尔代数、组合逻辑电路、时序逻辑电路、有限状态机与 Verilog 设计。</p><p><a href="/my_note/dldnote.html">进入课程笔记 →</a></p><hr><h3 id="fundamentals-of-data-structure" tabindex="-1">Fundamentals of Data Structure <a class="header-anchor" href="#fundamentals-of-data-structure" aria-label="Permalink to &quot;Fundamentals of Data Structure&quot;">​</a></h3><p>数据结构基础。</p><p>主要包括线性表、栈、队列、树、堆、图、排序、散列、最短路径、最小生成树与网络流等内容。</p><p><a href="/my_note/Fundamentals_of_Data_Structure.html">进入课程笔记 →</a></p><hr><h3 id="discrete-mathematics" tabindex="-1">Discrete Mathematics <a class="header-anchor" href="#discrete-mathematics" aria-label="Permalink to &quot;Discrete Mathematics&quot;">​</a></h3><p>离散数学。</p><p>主要包括命题逻辑、谓词逻辑、集合、关系、函数、图论、组合计数与生成函数等内容。</p><p><a href="/my_note/Discrete_Mathematics.html">进入课程笔记 →</a></p><hr><h3 id="computer-organization" tabindex="-1">Computer Organization <a class="header-anchor" href="#computer-organization" aria-label="Permalink to &quot;Computer Organization&quot;">​</a></h3><p>计算机组成。</p><p>主要包括数据表示、指令系统、CPU、控制器、存储器、数据通路、流水线与性能分析等内容。</p><p><a href="/my_note/Computer_Organization.html">进入课程笔记 →</a></p><h2 id="study-checklist" tabindex="-1">Study Checklist <a class="header-anchor" href="#study-checklist" aria-label="Permalink to &quot;Study Checklist&quot;">​</a></h2><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-0" disabled="disabled"><label class="task-list-item-label" for="task-item-0"> 阅读课程基本概念</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-1" disabled="disabled"><label class="task-list-item-label" for="task-item-1"> 整理公式、定义与定理</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-2" disabled="disabled"><label class="task-list-item-label" for="task-item-2"> 完成典型例题</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-3" disabled="disabled"><label class="task-list-item-label" for="task-item-3"> 总结易错点</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-4" disabled="disabled"><label class="task-list-item-label" for="task-item-4"> 尝试独立解释每一个核心概念</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-5" disabled="disabled"><label class="task-list-item-label" for="task-item-5"> 复习时回顾自己的错误记录</label></li></ul><h2 id="a-small-reminder" tabindex="-1">A Small Reminder <a class="header-anchor" href="#a-small-reminder" aria-label="Permalink to &quot;A Small Reminder&quot;">​</a></h2><p>学习计算机课程时，最重要的并不是记住所有结论，而是能够回答：</p><ul><li>这个概念到底在解决什么问题？</li><li>为什么要这样设计？</li><li>它和前面的知识有什么联系？</li><li>换一种题目形式后，我还能不能自己推出答案？</li></ul><blockquote><p>Keep learning. Keep building. Keep thinking.</p></blockquote><p>Have a nice day!</p>',44)])])}const p=e(s,[["render",r]]);export{u as __pageData,p as default};
